        public void clicked()
        {
            RecId                               entitlementObjectRecId;

            Dialog                              dialog = new Dialog("Link tables to entitlement object");
            DialogField                         dialogFieldTableNames;

            str                                 existingTablesCsv = '';
            str                                 tableNamesRaw;

            List                                tableNameList;
            ListEnumerator                      tableNameEnumerator;
            str                                 tableNameTrimmed;

            DEVLicenseTablesObjectLink          tablesObjectLink;
            int                                 createdCount = 0;
            int                                 skippedCount = 0;
            ;
            entitlementObjectRecId = DEVLicenseReportUserLines.EntitlementObject;

            if (!entitlementObjectRecId)
            {
                warning("EntitlementObject is empty on the current record.");
                return;
            }

            // Build initial value from existing links in DEVLicenseTablesObjectLink
            while select tablesObjectLink
                order by tablesObjectLink.TableName
				where tablesObjectLink.EntitlementObject == entitlementObjectRecId &&
				     tablesObjectLink.TableName

            {
                if (existingTablesCsv == '')
                {
                    existingTablesCsv = tablesObjectLink.TableName;
                }
                else
                {
                    existingTablesCsv = strFmt('%1, %2', existingTablesCsv, tablesObjectLink.TableName);
                }
            }

            // Build dialog and pre-populate
            dialogFieldTableNames = dialog.addField(extendedTypeStr(Notes), "Table names (comma-separated)");
            dialogFieldTableNames.value(existingTablesCsv);

            if (!dialog.run())
            {
                return; // user cancelled
            }

            tableNamesRaw = strLRTrim(dialogFieldTableNames.value());

            if (!tableNamesRaw)
            {
                warning("No table names provided.");
                return;
            }

            // Split by comma
            tableNameList = Global::strSplit(tableNamesRaw, ',');

            ttsbegin;

            tableNameEnumerator = tableNameList.getEnumerator();
            while (tableNameEnumerator.moveNext())
            {
                tableNameTrimmed = strLRTrim(tableNameEnumerator.current());

                if (!tableNameTrimmed)
                {
                    continue;
                }

                tablesObjectLink.clear();
                select firstOnly RecId from tablesObjectLink
					where tablesObjectLink.EntitlementObject == entitlementObjectRecId
					   && tablesObjectLink.TableName          == tableNameTrimmed;

                if (tablesObjectLink.RecId)
                {
                    skippedCount++;
                    continue;
                }

                tablesObjectLink.clear();
                tablesObjectLink.EntitlementObject = entitlementObjectRecId;
                tablesObjectLink.TableName         = tableNameTrimmed;
                tablesObjectLink.insert();

                createdCount++;
            }

            ttscommit;

            DEVLicenseReportUserLines_ds.reread();
            DEVLicenseReportUserLines_ds.refresh();

            DEVLicenseTablesObjectLink_ds.research(true);
            info(strFmt("Done. Created: %1, Skipped (already existed): %2", createdCount, skippedCount));


        }
